from flask import Flask, request, jsonify
import jwt
from functools import wraps
from typing import Dict

app = Flask(__name__)

def authenticate(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization', None)
        try:
            payload: Dict = verify_token(token)
            return f(payload=payload, *args, **kwargs)
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError as e:
            return jsonify({'error': str(e)}), 401
    return decorated_function

def verify_token(token: str) -> Dict:
    if not token:
        raise jwt.InvalidTokenError('Missing or invalid token')
    
    try:
        payload = jwt.decode(token, app.config['JWT_SECRET_KEY'], algorithms=['HS256', 'RS256'])
    except Exception as e:
        raise jwt.InvalidTokenError(str(e))
    
    return payload

@app.route('/protected', methods=['GET'])
@authenticate
def protected(payload: Dict):
    return jsonify({'message': f'Hello {payload["username"]}'}), 200

